INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$0a7469bd-1ce8-4b89-8f89-62bba17eb1ca$tag$, $tag$2026012800111$tag$, $tag$Jackson Marques (5582988165086)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, jĂĄ preenchi meus dados na pĂĄgina Teologia EAD e quero mais informaĂ§Ă”es.","time":"28/01/2026 13:30:32"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passarĂĄ todas as informaĂ§Ă”es.","time":"28/01/2026 13:30:33"},{"role":"client","text":"Seja bem-vindo Ă  Cidade Viva. Sou Karina Pimentel","time":"28/01/2026 13:53:36"},{"role":"agent","text":"*Karina Pimentel:* A nossa *GraduaĂ§ĂŁo em Teologia EAD* Ă© Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duraĂ§ĂŁo de 3 anos.\n\nNo formato EAD, as aulas sĂŁo ao vivo e gravadas e ficam Ă  disposiĂ§ĂŁo do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terĂŁo dia e horĂĄrio definidos previamente e poderĂŁo ser assistidas posteriormente, pois ficarĂŁo gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, atravĂ©s da Plataforma Virtual da FICV (Plataforma Moodle), alĂ©m de contar com materiais de apoio acadĂȘmico-cientĂ­fico.","time":"28/01/2026 13:53:58","feedback":"đ© Script Engessado: VocĂȘ enviou um bloco grande de informaĂ§Ă”es sem antes entender a dĂșvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* GraduaĂ§ĂŁo EAD em Teologia por apenas R$ 399,70/mĂȘs! đ€© Aproveite a condiĂ§ĂŁo especial: 10% de desconto na pontualidade durante toda a graduaĂ§ĂŁo, reduzindo o valor para R$ 359,73 por mĂȘs! đ Usando o cupom *BOLSA10*\n\nâš Sem taxa de matrĂ­cula! A primeira mensalidade Ă© paga no ato da inscriĂ§ĂŁo, e a prĂłxima apenas no mĂȘs de inĂ­cio das aulas.\n\nđ„ Valor promocional: Semestralidade por R$ 2.158,38!\n\nâ  AtenĂ§ĂŁo: O valor mensal pode variar de acordo com a data de matrĂ­cula:\n\nMatrĂ­culas realizadas atĂ© em JANEIRO: 6 mensalidades de R$ 359,73 = R$ 2.158,38\nMatrĂ­culas realizadas atĂ© em FEVEREIRO: 5 mensalidades de R$ 431,67 = R$2.158,38\nMatrĂ­culas realizadas atĂ© MARĂO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n\nđïž InĂ­cio das aulas: Fevereiro de 2026 đđ»","time":"28/01/2026 13:54:06","feedback":"đ© Script Engessado: VocĂȘ enviou um bloco grande de informaĂ§Ă”es sem antes entender a dĂșvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:*  \n Bom dia! Ficou alguma dĂșvida? O que estĂĄ faltando para vocĂȘ dar esse passo e ingressar no curso? Tenho certeza de que serĂĄ transformador em sua vida. đ","time":"29/01/2026 10:39:22","feedback":"đĄ ConduĂ§ĂŁo: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nJackson Marques, esperamos que sua solicitaĂ§ĂŁo tenha sido totalmente resolvida.\n\nO seu feedback Ă© muito importante para nĂłs, entĂŁo agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre Ă  disposiĂ§ĂŁo!","time":"29/01/2026 18:12:37"},{"role":"client","text":"Sua sessĂŁo irĂĄ expirar em 2 minutos!","time":"31/01/2026 13:51:37"},{"role":"client","text":"Sua sessĂŁo expirou!","time":"31/01/2026 13:53:39"}]$tag$, $tag$2026-01-28 13:30:32+00$tag$, FALSE, FALSE, 6.6, $tag$2026-03-01 16:46:57.607947+00$tag$, 7, 10, 5, 2, 9, 3, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content